const listDueRecurrences = `-- name: ListDueRecurrences :many
SELECT id, expense_id, organisation_id, frequency, next_recurs_on, end_date, is_active, created_at, updated_at FROM expense_recurrence
WHERE next_recurs_on <= CURRENT_DATE   -- due today or overdue
  AND is_active      = TRUE
  AND (end_date IS NULL OR end_date >= CURRENT_DATE)
ORDER BY next_recurs_on ASC
`

// -----------------------------------------------------------------------------
// ListDueRecurrences
// Returns all active recurrences that are due today or overdue.
// This is the query your cron job / scheduler runs daily to generate new
// expense copies. It returns the recurrence rows; the service then fetches
// the template expense and creates a new copy for each one.
// -----------------------------------------------------------------------------
func (q *Queries) ListDueRecurrences(ctx context.Context) ([]ExpenseRecurrence, error) {
	rows, err := q.db.Query(ctx, listDueRecurrences)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ExpenseRecurrence
	for rows.Next() {
		var i ExpenseRecurrence
		if err := rows.Scan(
			&i.ID,
			&i.ExpenseID,
			&i.OrganisationID,
			&i.Frequency,
			&i.NextRecursOn,
			&i.EndDate,
			&i.IsActive,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

