const updateRecurrenceNextDate = `-- name: UpdateRecurrenceNextDate :one
UPDATE expense_recurrence SET
    next_recurs_on = $2,
    updated_at     = now()
WHERE expense_id = $1
RETURNING id, expense_id, organisation_id, frequency, next_recurs_on, end_date, is_active, created_at, updated_at
`

type UpdateRecurrenceNextDateParams struct {
	ExpenseID    uuid.UUID   `json:"expense_id"`
	NextRecursOn pgtype.Date `json:"next_recurs_on"`
}

// -----------------------------------------------------------------------------
// UpdateRecurrenceNextDate
// After a recurrence fires and a new expense is created, advance the
// next_recurs_on date. The service layer calculates the next date based on
// frequency (e.g. add 1 month) and passes it here.
// -----------------------------------------------------------------------------
func (q *Queries) UpdateRecurrenceNextDate(ctx context.Context, arg UpdateRecurrenceNextDateParams) (ExpenseRecurrence, error) {
	row := q.db.QueryRow(ctx, updateRecurrenceNextDate, arg.ExpenseID, arg.NextRecursOn)
	var i ExpenseRecurrence
	err := row.Scan(
		&i.ID,
		&i.ExpenseID,
		&i.OrganisationID,
		&i.Frequency,
		&i.NextRecursOn,
		&i.EndDate,
		&i.IsActive,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}
